   229→  function copyCopy(headline, subheadline, btn) {
   230→    var text = headline + '\n\n' + subheadline;
   231→    function markCopied() {
   232→      btn.classList.add('copied');
   233→      var original = btn.textContent;
   234→      btn.textContent = 'Copiado!';
   235→      setTimeout(function () {
   236→        btn.classList.remove('copied');
   237→        btn.textContent = original;
   238→      }, 2000);
   239→    }
   240→    if (navigator.clipboard && navigator.clipboard.writeText) {
   241→      navigator.clipboard.writeText(text).then(markCopied).catch(function () {
   242→        fallbackCopy(text);
   243→        markCopied();
   244→      });
   245→    } else {
   246→      fallbackCopy(text);
   247→      markCopied();
   248→    }
   249→  }
   250→
   251→  function fallbackCopy(text) {
   252→    var ta = document.createElement('textarea');
   253→    ta.value = text;
   254→    ta.style.position = 'fixed';
   255→    ta.style.opacity = '0';
   256→    document.body.appendChild(ta);
   257→    ta.select();
   258→    document.execCommand('copy');
   259→    document.body.removeChild(ta);
   260→  }
